sys_script.script:
/**
 * After Update: Records audit information in work_notes for important changes.
 * Tracks: priority, assignment_group, assigned_to, state changes.
 * Globals: current, previous, gs
 */
(function executeRule(current, previous) {
    var auditEntries = [];
    var timestamp = new GlideDateTime().getDisplayValue();
    var user = gs.getUserDisplayName();

    // Audit priority changes
    if (current.getValue('priority') != previous.getValue('priority')) {
        auditEntries.push(
            '[AUDIT] Priority changed from ' +
            previous.priority.getDisplayValue() +
            ' to ' +
            current.priority.getDisplayValue()
        );
    }

    // Audit assignment group changes
    if (current.getValue('assignment_group') != previous.getValue('assignment_group')) {
        auditEntries.push(
            '[AUDIT] Assignment Group changed from "' +
            previous.assignment_group.getDisplayValue() +
            '" to "' +
            current.assignment_group.getDisplayValue() + '"'
        );
    }

    // Audit assigned_to changes
    if (current.getValue('assigned_to') != previous.getValue('assigned_to')) {
        auditEntries.push(
            '[AUDIT] Assigned To changed from "' +
            previous.assigned_to.getDisplayValue() +
            '" to "' +
            current.assigned_to.getDisplayValue() + '"'
        );
    }

    // Audit state changes
    if (current.getValue('state') != previous.getValue('state')) {
        auditEntries.push(
            '[AUDIT] State changed from "' +
            previous.state.getDisplayValue() +
            '" to "' +
            current.state.getDisplayValue() + '"'
        );
    }

    // Write all audit entries to work_notes in a single update
    if (auditEntries.length > 0) {
        var workNote = auditEntries.join('\n') + '\n[By: ' + user + ' at ' + timestamp + ']';
        var gr = new GlideRecord('x_2091449_manage_0_consumer_case');
        if (gr.get(current.getUniqueValue())) {
            gr.work_notes = workNote;
            gr.setWorkflow(false);
            gr.update();
        }
    }
})(current, previous);
